  };

  const handleBackToRooms = () => {
    setBookingStep('rooms');
    setSelectedRoom(null);
    setModalCheckIn('');
    setModalCheckOut('');
    setBookedDates([]);
  };

  const handleCheckAvailability = async () => {
    if (!modalCheckIn || !modalCheckOut) {
      setAlertModal({
        isOpen: true,
        title: 'Dates Required',
        message: 'Please select both check-in and check-out dates',
        type: 'error'
      });
      return;
    }

    if (numberOfNights <= 0) {
      setAlertModal({
        isOpen: true,
        title: 'Invalid Dates',
        message: 'Check-out date must be after check-in date',
        type: 'error'
      });
      return;
    }

    const hasConflict = bookedDates.includes(modalCheckIn) || bookedDates.includes(modalCheckOut);
    
    if (hasConflict) {
      setAlertModal({
        isOpen: true,
        title: 'Dates Not Available',
        message: 'Your selected check-in or check-out date is already occupied. Please choose different dates.',
        type: 'error'
      });
      return;
    }

    try {
      setLoading(true);
      await handleConfirmBooking();
    } catch (err) {
      setLoading(false);
    }
  };

  const handleConfirmBooking = async () => {
    try {
      const bookingData = {
        hotel: selectedHotel.id,
        room: selectedRoom._id,
        checkIn: modalCheckIn,
        checkOut: modalCheckOut,
        guests: selectedGuests,
        totalPrice: selectedRoom.pricePerNight * numberOfNights
      };
      
      const response = await createBooking(bookingData);
      if (response.success) {
        setBookingSuccess(true);
        setTimeout(() => {
          setBookingSuccess(false);
          setSelectedHotel(null);
          setSelectedRoom(null);
          setModalCheckIn('');
          setModalCheckOut('');
          setBookingStep('rooms');
          setBookedDates([]);
          setActiveTab('bookings');
        }, 2000);
      }
    } catch (err) {
      setLoading(false);
      if (err.response?.status === 409) {
        const errorMsg = err.response?.data?.error || 'This room is already booked for these dates.';
        setAlertModal({
          isOpen: true,
          title: 'Room Already Occupied',
          message: errorMsg,
          type: 'error'
        });
      } else {
        setAlertModal({
          isOpen: true,
          title: 'Booking Failed',
          message: err.response?.data?.error || err.message,
          type: 'error'
        });
      }
    }
  };

  const closeAlertModal = () => {
    setAlertModal(prev => ({ ...prev, isOpen: false }));
  };
const formatDate = (dateString) => {
  if (!dateString) return '';
  
  const date = new Date(dateString);
  
  if (isNaN(date.getTime())) return 'Invalid Date';
  
  return date.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
};

const formatDateLong = (dateString) => {
  if (!dateString) return '';
  
  const date = new Date(dateString);
  
  if (isNaN(date.getTime())) return 'Invalid Date';
  
  return date.toLocaleDateString('en-GB', {
    day: 'numeric',
    month: 'long',
    year: 'numeric'
  });
};
// ✅ FIXED "today"
const now = new Date();
const today = new Date(
